// Bicep: parameterized tags applied to multiple resources

@description('Tag values for this deployment')
param tags object = {
  CostCenter: 'eng-platform'
  Environment: 'prod'
  Owner: 'platform-team'
  ManagedBy: 'bicep'
}

resource rg 'Microsoft.Resources/resourceGroups@2022-09-01' = {
  name: 'rg-prod-web'
  location: 'eastus2'
  tags: tags
}

resource storageAccount 'Microsoft.Storage/storageAccounts@2023-01-01' = {
  name: 'stprodweb${uniqueString(rg.id)}'
  location: rg.location
  tags: tags  // same tags object applied to every resource
  sku: { name: 'Standard_LRS' }
  kind: 'StorageV2'
}

resource appServicePlan 'Microsoft.Web/serverfarms@2022-09-01' = {
  name: 'asp-prod-web'
  location: rg.location
  tags: tags
  sku: { name: 'P1v3', tier: 'PremiumV3' }
}

// Union tags — merge deployment tags with resource-specific tags
resource vm 'Microsoft.Compute/virtualMachines@2023-07-01' = {
  name: 'vm-prod-web-01'
  location: rg.location
  tags: union(tags, {
    Role: 'web-server'
    PatchGroup: 'group-a'
  })
  properties: { /* ... */ }
}

# variables.tf
variable "environment" {
  type    = string
  default = "prod"
}

variable "cost_center" {
  type = string
}

# locals.tf
locals {
  common_tags = {
    CostCenter  = var.cost_center
    Environment = var.environment
    ManagedBy   = "terraform"
    Owner       = "platform-team"
  }
}

# main.tf
resource "azurerm_resource_group" "prod_web" {
  name     = "rg-prod-web"
  location = "eastus2"
  tags     = local.common_tags
}

# Resource with merged extra tags
resource "azurerm_linux_virtual_machine" "web" {
  name                = "vm-prod-web-01"
  resource_group_name = azurerm_resource_group.prod_web.name
  location            = azurerm_resource_group.prod_web.location
  size                = "Standard_D2s_v3"

  # Merge common tags with resource-specific tags
  tags = merge(local.common_tags, {
    Role       = "web-server"
    PatchGroup = "group-a"
  })

  # other required properties...
}

# Storage account
resource "azurerm_storage_account" "prod_web" {
  name                     = "stprodweb${substr(md5(azurerm_resource_group.prod_web.id), 0, 8)}"
  resource_group_name      = azurerm_resource_group.prod_web.name
  location                 = azurerm_resource_group.prod_web.location
  account_tier             = "Standard"
  account_replication_type = "LRS"
  tags                     = local.common_tags
}
